              <div className="grid gap-8 lg:grid-cols-2">
                {/* Difficulty Pie Chart */}
                <div className="flex flex-col">
                  <h3 className="text-[12px] font-medium uppercase tracking-[0.06em] text-text-tertiary mb-4">Difficulty Split</h3>
