                            <Cell key={entry.name} fill={difficultyColors[entry.name as DsaDifficulty]} stroke="rgba(255,255,255,0.06)" />
                          ))}
                        </Pie>
                        <Tooltip contentStyle={{ borderRadius: "8px", border: "1px solid rgba(255,255,255,0.10)", background: "#1A1A1E", color: "#F2F2F3", boxShadow: "0 8px 24px rgba(0,0,0,0.5)", fontSize: "12px", padding: "8px 12px" }} itemStyle={{ color: "#F2F2F3" }} />
                      </PieChart>
                    </ResponsiveContainer>
                  </div>
                </div>

                {/* Topic Bar Chart */}
                <div className="flex flex-col">
                  <h3 className="text-[12px] font-medium uppercase tracking-[0.06em] text-text-tertiary mb-4">Topic Spread</h3>
                  <div className="h-[180px]">
                    <ResponsiveContainer width="100%" height="100%">
                      <BarChart data={topicProgress.slice(0, 5)} layout="vertical" margin={{ left: -10, right: 0, top: 0, bottom: 0 }}>
                        <CartesianGrid strokeDasharray="0" horizontal={false} stroke="rgba(255,255,255,0.04)" />
                        <XAxis type="number" tickLine={false} axisLine={false} tick={{ fill: "#505055", fontSize: 10 }} />
                        <YAxis type="category" dataKey="topic" width={80} tickLine={false} axisLine={false} tick={{ fill: "#8A8A8F", fontSize: 11 }} />
                        <Tooltip cursor={{ fill: "rgba(255,255,255,0.02)" }} contentStyle={{ borderRadius: "8px", border: "1px solid rgba(255,255,255,0.10)", background: "#1A1A1E", color: "#F2F2F3", boxShadow: "0 8px 24px rgba(0,0,0,0.5)", fontSize: "12px", padding: "8px 12px" }} itemStyle={{ color: "#CBA365" }} />
                        <Bar dataKey="solved" fill="#CBA365" radius={[0, 4, 4, 0]} barSize={20} />
                      </BarChart>
                    </ResponsiveContainer>
                  </div>
                </div>
              </div>
            </section>

            <section className="rounded-xl border border-border bg-surface p-6 shadow-card hover:border-border-hover transition-all duration-200">
              <div className="flex items-center justify-between mb-4">
                <h2 className="text-[14px] font-medium text-text-primary">Problem Log</h2>
                <div className="flex gap-2 text-[11px] font-medium">
                  <span className="text-warning bg-warning/10 px-2 py-0.5 rounded border border-warning/20">{revisionCount} Revision</span>
                  <span className="text-text-secondary bg-surface-raised px-2 py-0.5 rounded border border-border">{filteredProblems.length} Total</span>
                </div>
              </div>

              {/* Dense List View */}
              <div className="flex flex-col">
                <AnimatePresence initial={false}>
                  {filteredProblems.length ? (
                    filteredProblems.slice(0, 10).map((problem) => (
                      <motion.div
                        key={problem.id}
                        initial={{ opacity: 0, height: 0 }}
                        animate={{ opacity: 1, height: "auto" }}
                        exit={{ opacity: 0, height: 0 }}
                        className="group flex flex-col py-3 border-b border-border last:border-0"
                      >
                        <div className="flex items-start justify-between">
                          <div className="flex flex-col gap-1 min-w-0 pr-4">
                            <div className="flex items-center gap-2">
                              {problem.revisionRequired && <div className="h-1.5 w-1.5 rounded-full bg-warning shrink-0" title="Needs Revision" />}
                              <span className="text-[13px] font-medium text-text-primary truncate">{problem.name}</span>
                            </div>
                            <span className="text-[11px] text-text-secondary truncate">
                              {problem.platform} · <span className={
                                problem.difficulty === "Easy" ? "text-text-secondary" : 
                                problem.difficulty === "Medium" ? "text-accent" : "text-destructive"
                              }>{problem.difficulty}</span> · {problem.topic}
                            </span>
                            {problem.notes && (
                              <p className="text-[11px] text-text-tertiary mt-1 italic truncate border-l-2 border-border pl-2">
                                &quot;{problem.notes}&quot;
                              </p>
                            )}
                          </div>
                          <div className="flex flex-col items-end shrink-0 gap-2">
                            <span className="text-[10px] uppercase tracking-wider text-text-tertiary">
                              {formatSolvedDate(problem.solvedDate)}
                            </span>
                            <button onClick={() => deleteProblem(problem.id)} className="opacity-0 group-hover:opacity-100 transition-opacity text-text-tertiary hover:text-destructive">
                              <Trash2 className="h-3.5 w-3.5" />
                            </button>
                          </div>
                        </div>
                      </motion.div>
                    ))
                  ) : (
                    <div className="py-8 text-center flex flex-col items-center text-[12px] text-text-tertiary">
                      <BookOpenText className="h-8 w-8 mb-3 opacity-50" />
                      No DSA problems logged yet.
                    </div>
                  )}
                </AnimatePresence>
                {filteredProblems.length > 10 && <div className="pt-3 text-[12px] text-accent text-center cursor-pointer">View all ({filteredProblems.length}) →</div>}
              </div>
            </section>
          </motion.div>
        </div>
      </motion.div>
    </div>
  );
}

function FormError({ message }: { message?: string }) {
  if (!message) return null;
  return <p className="text-[11px] text-destructive mt-1">{message}</p>;
}

"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import { AnimatePresence, motion } from "framer-motion";
import {
  CalendarClock,
  CheckCircle2,
  FlagTriangleRight,
  Goal as GoalIcon,
  Plus,
  RotateCcw,
  Search,
  Sparkles,
  Trash2,
} from "lucide-react";
import { useEffect, useMemo, useState, type SelectHTMLAttributes } from "react";
import { useForm } from "react-hook-form";
import { toast } from "sonner";
import { z } from "zod";

import {
  loadGoals,
  saveGoals,
} from "@/features/goal-tracker/goal-tracker-storage";
import { useAuth } from "@/features/auth/auth-context";
import {
  daysLeft,
  formatGoalDeadline,
  getGoalCompletionRate,
  getScopeProgress,
  isOverdue,
} from "@/features/goal-tracker/goal-tracker-utils";
import {
  goalScopes,
  type Goal,
  type GoalScope,
} from "@/features/goal-tracker/goal-tracker-types";

const goalSchema = z.object({
  title: z.string().min(2, "Add a goal title."),
  scope: z.enum(goalScopes),
  target: z.coerce.number().min(1, "Target must be at least 1."),
  progress: z.coerce.number().min(0, "Progress cannot be negative."),
  deadline: z.string().min(1, "Pick a deadline."),
  notes: z.string().max(500, "Keep notes under 500 characters.").default(""),
});

type GoalFormValues = z.output<typeof goalSchema>;

// Animation configurations
const staggerContainer = {
  hidden: { opacity: 0 },
  show: {
    opacity: 1,
    transition: { staggerChildren: 0.08, delayChildren: 0.2 }
  }
};

const staggerItem = {
  hidden: { opacity: 0, y: 24 },
  show: { opacity: 1, y: 0, transition: { duration: 0.5, ease: [0.25, 0.1, 0.25, 1] as [number, number, number, number] } }
};

export function GoalTrackerClient() {
  const { user } = useAuth();
  const [hydrated, setHydrated] = useState(false);
  const [goals, setGoals] = useState<Goal[]>([]);
  const [search, setSearch] = useState("");
  const [scopeFilter, setScopeFilter] = useState<GoalScope | "all">("all");

  const form = useForm<z.input<typeof goalSchema>, unknown, GoalFormValues>({
    resolver: zodResolver(goalSchema),
    defaultValues: {
      title: "",
      scope: "Monthly",
      target: 10,
      progress: 0,
      deadline: new Date().toISOString().slice(0, 10),
      notes: "",
    },
  });

  useEffect(() => {
    async function init() {
      if (!user) return;
      const stored = await loadGoals(user.uid);
      setGoals(stored);
      setHydrated(true);
    }
    init();
  }, [user]);

  const filteredGoals = useMemo(() => {
    const normalized = search.trim().toLowerCase();
    return goals
      .filter((goal) => (scopeFilter === "all" ? true : goal.scope === scopeFilter))
      .filter((goal) => {
        if (!normalized) return true;
        return [goal.title, goal.scope, goal.notes].some((value) =>
          value.toLowerCase().includes(normalized),
        );
      })
      .sort((left, right) => new Date(left.deadline).getTime() - new Date(right.deadline).getTime());
  }, [goals, scopeFilter, search]);

  const monthly = getScopeProgress(goals, "Monthly");
  const quarterly = getScopeProgress(goals, "Quarterly");
  const yearly = getScopeProgress(goals, "Yearly");
  const completionRate = getGoalCompletionRate(goals);

  function addGoal(values: GoalFormValues) {
    const goal: Goal = {
      id: crypto.randomUUID(),
      title: values.title,
      scope: values.scope,
      target: values.target,
      progress: values.progress,
      deadline: new Date(`${values.deadline}T09:00:00`).toISOString(),
      notes: values.notes ?? "",
      completed: values.progress >= values.target,
      createdAt: new Date().toISOString(),
    };

    const nextGoals = [goal, ...goals];
    setGoals(nextGoals);
    if (user) saveGoals(user.uid, nextGoals);

    form.reset({
      title: "",
      scope: values.scope,
      target: values.target,
      progress: values.progress,
      deadline: values.deadline,
      notes: "",
    });
    toast.success("Goal saved.");
  }

  function updateGoal(id: string, patch: Partial<Goal>) {
    const nextGoals = goals.map((goal) =>
      goal.id === id
        ? {
            ...goal,
            ...patch,
            completed: patch.completed ?? (patch.progress !== undefined ? patch.progress >= goal.target : goal.completed),
          }
        : goal,
    );
    setGoals(nextGoals);
    if (user) saveGoals(user.uid, nextGoals);
  }

  function removeGoal(id: string) {
    const nextGoals = goals.filter((goal) => goal.id !== id);
    setGoals(nextGoals);
    if (user) saveGoals(user.uid, nextGoals);
    toast.success("Goal removed.");
  }

  function resetWorkspace() {
    setGoals([]);
    if (user) saveGoals(user.uid, []);
    setSearch("");
    setScopeFilter("all");
    toast.message("Goal workspace cleared.");
  }

  if (!hydrated) {
    return (
      <div className="space-y-6">
        <div className="h-10 w-48 bg-surface animate-pulse rounded" />
        <div className="h-[300px] w-full bg-surface animate-pulse rounded-xl border border-border" />
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-12 pb-16">

      {/* ════════════ HEADER ════════════ */}
      <motion.div
        initial={{ opacity: 0, y: 16 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.4, delay: 0.1, ease: [0.25, 0.1, 0.25, 1] as [number, number, number, number] }}
        className="flex flex-col md:flex-row md:items-end justify-between gap-6"
      >
        <div>
          <h1 className="text-[28px] font-medium tracking-tight text-text-primary">
            Goal Tracker
          </h1>
          <p className="mt-1 text-[15px] text-text-secondary">
            Set and execute on macro milestones.
          </p>
        </div>
        <div className="flex items-center gap-3">
          <span className="text-[13px] font-medium text-text-secondary">{filteredGoals.length} goals</span>
          <span className="text-text-tertiary">|</span>
          <button 
            onClick={resetWorkspace} 
            className="flex items-center gap-2 text-[13px] font-medium text-text-secondary hover:text-text-primary transition-colors"
          >
            <RotateCcw className="h-4 w-4" /> Reset
          </button>
        </div>
      </motion.div>

      <motion.div variants={staggerContainer} initial="hidden" animate="show" className="flex flex-col gap-10">

        {/* ════════════ TYPOGRAPHIC STATS ════════════ */}
        <motion.section variants={staggerItem} className="grid grid-cols-2 md:grid-cols-4 gap-8 py-6 border-y border-border">
          <div className="flex flex-col">
            <span className="text-[11px] text-text-tertiary uppercase tracking-widest font-medium mb-1">Monthly</span>
            <span className="text-[28px] text-text-primary font-medium tracking-tight">{monthly.completed}<span className="text-[20px] text-text-tertiary">/{monthly.total}</span></span>
          </div>
          <div className="flex flex-col">
            <span className="text-[11px] text-accent uppercase tracking-widest font-medium mb-1">Quarterly</span>
            <span className="text-[28px] text-text-primary font-medium tracking-tight">{quarterly.completed}<span className="text-[20px] text-text-tertiary">/{quarterly.total}</span></span>
          </div>
          <div className="flex flex-col">
            <span className="text-[11px] text-text-secondary uppercase tracking-widest font-medium mb-1">Yearly</span>
            <span className="text-[28px] text-text-primary font-medium tracking-tight">{yearly.completed}<span className="text-[20px] text-text-tertiary">/{yearly.total}</span></span>
          </div>
          <div className="flex flex-col">
            <span className="text-[11px] text-text-secondary uppercase tracking-widest font-medium mb-1">Win Rate</span>
            <span className="text-[28px] text-text-primary font-medium tracking-tight">{completionRate}<span className="text-[20px] text-text-tertiary">%</span></span>
          </div>
        </motion.section>

        {/* ════════════ TWO COLUMN LAYOUT ════════════ */}
        <div className="grid grid-cols-1 xl:grid-cols-[0.8fr_1.2fr] gap-8">

          {/* LEFT: Add Goal */}
          <motion.div variants={staggerItem} className="flex flex-col gap-8">
            <section className="rounded-xl border border-border bg-surface p-6 shadow-card hover:border-border-hover transition-all duration-200">
              <h2 className="text-[14px] font-medium text-text-primary mb-6">Create Goal</h2>

              <form className="space-y-4" onSubmit={form.handleSubmit(addGoal)}>
                <div className="space-y-2">
                  <label className="text-[12px] font-medium text-text-secondary">Title</label>
                  <input type="text" {...form.register("title")} className="w-full h-9 bg-background border border-border rounded-md px-3 text-[13px] text-text-primary focus:outline focus:outline-2 focus:outline-accent outline-offset-0 placeholder:text-text-tertiary transition-all" placeholder="E.g., Complete 100 LeetCode" />
                  <FormError message={form.formState.errors.title?.message} />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-[12px] font-medium text-text-secondary">Scope</label>
                    <select {...form.register("scope")} className="w-full h-9 bg-background border border-border rounded-md px-3 text-[13px] text-text-primary focus:outline focus:outline-2 focus:outline-accent outline-offset-0 transition-all">
                      {goalScopes.map((scope) => <option key={scope} value={scope}>{scope}</option>)}
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[12px] font-medium text-text-secondary">Deadline</label>
                    <input type="date" {...form.register("deadline")} className="w-full h-9 bg-background border border-border rounded-md px-3 text-[13px] text-text-primary focus:outline focus:outline-2 focus:outline-accent outline-offset-0 transition-all" />
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-[12px] font-medium text-text-secondary">Target</label>
                    <input type="number" min={1} {...form.register("target")} className="w-full h-9 bg-background border border-border rounded-md px-3 text-[13px] text-text-primary focus:outline focus:outline-2 focus:outline-accent outline-offset-0 transition-all" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[12px] font-medium text-text-secondary">Progress</label>
                    <input type="number" min={0} {...form.register("progress")} className="w-full h-9 bg-background border border-border rounded-md px-3 text-[13px] text-text-primary focus:outline focus:outline-2 focus:outline-accent outline-offset-0 transition-all" />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[12px] font-medium text-text-secondary">Notes (Optional)</label>
                  <textarea {...form.register("notes")} className="w-full h-20 bg-background border border-border rounded-md px-3 py-2 text-[13px] text-text-primary focus:outline focus:outline-2 focus:outline-accent outline-offset-0 placeholder:text-text-tertiary transition-all resize-none" placeholder="Context..." />
                </div>

                <button type="submit" className="w-full h-9 mt-2 bg-accent text-background rounded-md text-[13px] font-semibold hover:opacity-90 transition-opacity flex items-center justify-center gap-2">
                  <Plus className="h-4 w-4" /> Save Goal
                </button>
              </form>
            </section>
          </motion.div>

          {/* RIGHT: Goal List */}
          <motion.div variants={staggerItem} className="flex flex-col gap-8">
            <section className="rounded-xl border border-border bg-surface p-6 shadow-card hover:border-border-hover transition-all duration-200">
              <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between mb-6 gap-4">
                <h2 className="text-[14px] font-medium text-text-primary">Master List</h2>

                <div className="flex gap-4 text-[12px] font-medium text-text-tertiary">
                  {["all", ...goalScopes].map((scope) => (
                    <button 
                      key={scope}
                      onClick={() => setScopeFilter(scope as GoalScope | "all")}
                      className={`transition-colors pb-1 ${scopeFilter === scope ? "text-text-primary border-b border-accent" : "hover:text-text-primary"}`}
                    >
                      {scope === "all" ? "All" : scope}
                    </button>
                  ))}
                </div>
              </div>

              <div className="relative mb-6">
                <Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-text-tertiary" />
                <input
                  type="text"
                  className="w-full h-9 bg-background border border-border rounded-md pl-9 pr-3 text-[13px] text-text-primary focus:outline focus:outline-2 focus:outline-accent outline-offset-0 placeholder:text-text-tertiary transition-all"
                  placeholder="Search goals..."
                  value={search}
                  onChange={(event) => setSearch(event.target.value)}
                />
              </div>

              <div className="flex flex-col border-t border-border">
                <AnimatePresence initial={false}>
                  {filteredGoals.length ? (
                    filteredGoals.map((goal) => {
                      const left = daysLeft(goal.deadline);
                      const overdue = isOverdue(goal);
                      const percent = Math.min((goal.progress / goal.target) * 100, 100);

                      return (
                        <motion.div
                          key={goal.id}
                          initial={{ opacity: 0, height: 0 }}
                          animate={{ opacity: 1, height: "auto" }}
                          exit={{ opacity: 0, height: 0 }}
                          className="group flex flex-col py-5 border-b border-border last:border-0"
                        >
                          <div className="flex items-start justify-between">
                            <div className="flex flex-col gap-1 min-w-0 pr-4 flex-1">
                              <div className="flex items-center justify-between w-full">
                                <span className="text-[14px] font-medium text-text-primary">{goal.title}</span>
                                <span className="text-[11px] font-medium uppercase tracking-wider text-text-tertiary shrink-0">
                                  {goal.completed ? "Done" : overdue ? "Overdue" : `${left}d`}
                                </span>
                              </div>
                              <span className="text-[12px] text-text-secondary">{goal.scope}</span>

                              <div className="flex items-center gap-3 mt-3">
                                <div className="h-1.5 flex-1 bg-background rounded-full overflow-hidden border border-border">
                                  <div 
                                    className={`h-full rounded-full transition-all duration-500 ${goal.completed ? "bg-text-secondary" : overdue ? "bg-destructive" : "bg-accent"}`}
                                    style={{ width: `${percent}%` }}
                                  />
                                </div>
                                <span className="text-[11px] font-medium text-text-primary shrink-0 w-8">{Math.round(percent)}%</span>
                              </div>

                              {goal.notes && (
                                <p className="text-[11px] text-text-tertiary mt-3 italic border-l-2 border-border pl-2 line-clamp-2">
                                  {goal.notes}
                                </p>
                              )}
                            </div>

                            <div className="flex flex-col items-end gap-2 shrink-0 ml-4 opacity-0 group-hover:opacity-100 transition-opacity">
                              <button onClick={() => updateGoal(goal.id, { progress: Math.min(goal.target, goal.progress + 1) })} className="text-[11px] font-medium text-text-secondary hover:text-accent">
                                +1 Progress
                              </button>
                              <button onClick={() => updateGoal(goal.id, { completed: !goal.completed })} className="text-[11px] font-medium text-text-secondary hover:text-text-primary">
                                {goal.completed ? "Reopen" : "Complete"}
                              </button>
                              <button onClick={() => removeGoal(goal.id)} className="text-[11px] font-medium text-text-secondary hover:text-destructive">
                                Delete
                              </button>
                            </div>
                          </div>
                        </motion.div>
                      );
                    })
                  ) : (
                    <div className="py-12 text-center text-[13px] text-text-tertiary">No goals found.</div>
                  )}
                </AnimatePresence>
              </div>
            </section>
          </motion.div>
        </div>
      </motion.div>
    </div>
  );
}

function FormError({ message }: { message?: string }) {
  if (!message) return null;
  return <p className="text-[11px] text-destructive mt-1">{message}</p>;
}

import { doc, getDoc, setDoc } from "firebase/firestore";
import type { Goal } from "@/features/goal-tracker/goal-tracker-types";
import { db } from "@/lib/firebase";

const STORAGE_KEY = "careeros.goal-tracker.v1";

export async function loadGoals(userId: string): Promise<Goal[]> {
  if (!db || !userId) return [];

  try {
    const docRef = doc(db, "users", userId, "goal-tracker", "state");
    const snap = await getDoc(docRef);
    if (snap.exists()) {
      const data = snap.data();
      return Array.isArray(data.goals) ? (data.goals as Goal[]) : [];
    }
  } catch (error) {
    console.error("Failed to load goals from Firestore:", error);
  }

  return [];
}

export async function saveGoals(userId: string, goals: Goal[]) {
  if (!db || !userId) return;

  try {
    const docRef = doc(db, "users", userId, "goal-tracker", "state");
    await setDoc(docRef, { goals }, { merge: true });
  } catch (error) {
    console.error("Failed to save goals to Firestore:", error);
  }
}

"use client";

import { AnimatePresence, motion } from "framer-motion";
import { Check, Dumbbell, Flame, Plus, RotateCcw, Search, Trash2 } from "lucide-react";
import { useEffect, useMemo, useState } from "react";
import { toast } from "sonner";

import {
  defaultHabitTrackerState,
  loadHabitTrackerState,
  saveHabitTrackerState,
} from "@/features/habit-tracker/habit-tracker-storage";
import {
  formatDayLabel,
  formatMonthLabel,
  getCurrentMonthGrid,
  getHeatmapCounts,
  getHabitCompletionRate,
  getHabitStreak,
  getOverallStreak,
  toDateKey,
} from "@/features/habit-tracker/habit-tracker-utils";
import type { Habit, HabitLog } from "@/features/habit-tracker/habit-tracker-types";
import { useAuth } from "@/features/auth/auth-context";

const presetHabits = [
  "DSA",
  "Gym",
  "Reading",
  "LinkedIn Post",
  "Water Intake",
  "Meditation",
] as const;

// Animation configurations
const staggerContainer = {
  hidden: { opacity: 0 },
  show: {
    opacity: 1,
    transition: { staggerChildren: 0.08, delayChildren: 0.2 }
  }
};

const staggerItem = {
  hidden: { opacity: 0, y: 24 },
  show: { opacity: 1, y: 0, transition: { duration: 0.5, ease: [0.25, 0.1, 0.25, 1] as [number, number, number, number] } }
};

export function HabitTrackerClient() {
  const { user } = useAuth();
  const [hydrated, setHydrated] = useState(false);
  const [habits, setHabits] = useState<Habit[]>([]);
  const [logs, setLogs] = useState<HabitLog[]>([]);
  const [newHabitName, setNewHabitName] = useState("");
  const [selectedHabitId, setSelectedHabitId] = useState<string>("");
  const [search, setSearch] = useState("");

  useEffect(() => {
    async function init() {
      if (!user) return;
      const state = await loadHabitTrackerState(user.uid);
      if (state.habits.length) {
        setHabits(state.habits);
      } else {
        const now = new Date().toISOString();
        setHabits(
          presetHabits.map((name) => ({
            id: crypto.randomUUID(),
            name,
            createdAt: now,
            preset: true,
          })),
        );
      }

      setLogs(state.logs);
      setHydrated(true);
    }
    init();
  }, [user]);

  const todayKey = toDateKey();
  const todayLogs = logs.filter((log) => log.date === todayKey && log.completed);
  const todayCompletedIds = new Set(todayLogs.map((log) => log.habitId));
  const currentHabit = habits.find((habit) => habit.id === selectedHabitId) ?? habits[0];
  const selectedHabitMetrics = currentHabit ? getHabitStreak(currentHabit.id, logs) : { current: 0, longest: 0 };
  const overallStreak = getOverallStreak(logs);
  const heatmapCounts = getHeatmapCounts(logs);
  const gridDays = getCurrentMonthGrid();
  const pastSevenDays = Array.from({ length: 7 }, (_, index) => {
    const date = new Date();
    date.setDate(date.getDate() - (6 - index));
    date.setHours(0, 0, 0, 0);
    return date;
  });

  const filteredHabits = useMemo(() => {
    const normalized = search.trim().toLowerCase();
    return habits.filter((habit) => habit.name.toLowerCase().includes(normalized));
  }, [habits, search]);

  useEffect(() => {
    if (!selectedHabitId && habits[0]) {
      setSelectedHabitId(habits[0].id);
    }
  }, [habits, selectedHabitId]);

  function addHabit() {
    const name = newHabitName.trim();
    if (!name) {
      toast.error("Enter a habit name first.");
      return;
    }

    const habit: Habit = {
      id: crypto.randomUUID(),
      name,
      createdAt: new Date().toISOString(),
      preset: false,
    };

    const nextHabits = [habit, ...habits];
    setHabits(nextHabits);
    if (user) saveHabitTrackerState(user.uid, { habits: nextHabits, logs });

    setNewHabitName("");
    toast.success("Habit added.");
  }

  function removeHabit(id: string) {
    const nextHabits = habits.filter((habit) => habit.id !== id);
    const nextLogs = logs.filter((log) => log.habitId !== id);
    setHabits(nextHabits);
    setLogs(nextLogs);
    if (user) saveHabitTrackerState(user.uid, { habits: nextHabits, logs: nextLogs });
    toast.success("Habit removed.");
  }

  function toggleToday(habitId: string) {
    const nextLogs = logs.map(log => ({...log}));
    const existing = nextLogs.find((log) => log.habitId === habitId && log.date === todayKey);

    if (existing) {
      const filtered = nextLogs.filter((log) => log.id !== existing.id);
      setLogs(filtered);
      if (user) saveHabitTrackerState(user.uid, { habits, logs: filtered });
    } else {
      const next = {
        id: crypto.randomUUID(),
        habitId,
        date: todayKey,
        completed: true,
      };
      const updated = [next, ...nextLogs];
      setLogs(updated);
      if (user) saveHabitTrackerState(user.uid, { habits, logs: updated });
    }
  }

  function resetWorkspace() {
    const now = new Date().toISOString();
    const newHabits = presetHabits.map((name) => ({
      id: crypto.randomUUID(),
      name,
      createdAt: now,
      preset: true,
    }));
    setHabits(newHabits);
    setLogs([]);
    if (user) saveHabitTrackerState(user.uid, { habits: newHabits, logs: [] });
    setNewHabitName("");
    setSearch("");
    setSelectedHabitId("");
    toast.message("Habit tracker reset.");
  }

  if (!hydrated) {
    return (
      <div className="space-y-6">
        <div className="h-10 w-48 bg-surface animate-pulse rounded" />
        <div className="h-[300px] w-full bg-surface animate-pulse rounded-xl border border-border" />
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-12 pb-16">

      {/* ════════════ HEADER ════════════ */}
      <motion.div
        initial={{ opacity: 0, y: 16 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.4, delay: 0.1, ease: [0.25, 0.1, 0.25, 1] as [number, number, number, number] }}
        className="flex flex-col md:flex-row md:items-end justify-between gap-6"
      >
        <div>
          <h1 className="text-[28px] font-medium tracking-tight text-text-primary">
            Habit Tracker
          </h1>
          <p className="mt-1 text-[15px] text-text-secondary">
            Daily consistency and long-term momentum.
          </p>
        </div>
        <div className="flex items-center gap-3">
          <span className="text-[13px] font-medium text-text-secondary">{habits.length} habits tracked</span>
          <span className="text-text-tertiary">|</span>
          <button 
            onClick={resetWorkspace} 
            className="flex items-center gap-2 text-[13px] font-medium text-text-secondary hover:text-text-primary transition-colors"
          >
            <RotateCcw className="h-4 w-4" /> Reset
          </button>
        </div>
      </motion.div>

      <motion.div variants={staggerContainer} initial="hidden" animate="show" className="flex flex-col gap-10">

        {/* ════════════ TYPOGRAPHIC STATS ════════════ */}
        <motion.section variants={staggerItem} className="grid grid-cols-2 md:grid-cols-4 gap-8 py-6 border-y border-border">
          <div className="flex flex-col">
            <span className="text-[11px] text-text-tertiary uppercase tracking-widest font-medium mb-1">Today</span>
            <span className="text-[28px] text-text-primary font-medium tracking-tight">{todayLogs.length}<span className="text-[20px] text-text-tertiary">/{habits.length || 1}</span></span>
          </div>
          <div className="flex flex-col">
            <span className="text-[11px] text-accent uppercase tracking-widest font-medium mb-1">Current Streak</span>
            <span className="text-[28px] text-text-primary font-medium tracking-tight">{selectedHabitMetrics.current}<span className="text-[20px] text-text-tertiary">d</span></span>
          </div>
          <div className="flex flex-col">
            <span className="text-[11px] text-text-secondary uppercase tracking-widest font-medium mb-1">Longest Streak</span>
            <span className="text-[28px] text-text-primary font-medium tracking-tight">{selectedHabitMetrics.longest}<span className="text-[20px] text-text-tertiary">d</span></span>
          </div>
          <div className="flex flex-col">
            <span className="text-[11px] text-text-secondary uppercase tracking-widest font-medium mb-1">Global Streak</span>
            <span className="text-[28px] text-text-primary font-medium tracking-tight">{overallStreak.current}<span className="text-[20px] text-text-tertiary">d</span></span>
          </div>
        </motion.section>

        {/* ════════════ TWO COLUMN LAYOUT ════════════ */}
        <div className="grid grid-cols-1 xl:grid-cols-[1.1fr_0.9fr] gap-8">

          {/* LEFT: Check-ins & Heatmap */}
          <motion.div variants={staggerItem} className="flex flex-col gap-8">
            <section className="rounded-xl border border-border bg-surface p-6 shadow-card hover:border-border-hover transition-all duration-200">
              <div className="flex items-center justify-between mb-6">
                <h2 className="text-[14px] font-medium text-text-primary">Today&apos;s Log</h2>
              </div>

              <div className="flex flex-col border-t border-border">
                <AnimatePresence initial={false}>
                  {filteredHabits.length ? (
                    filteredHabits.map((habit) => {
                      const completed = todayCompletedIds.has(habit.id);
                      const rate = getHabitCompletionRate(habit, logs);
                      const streak = getHabitStreak(habit.id, logs);

                      return (
                        <motion.div
                          key={habit.id}
                          initial={{ opacity: 0, height: 0 }}
                          animate={{ opacity: 1, height: "auto" }}
                          exit={{ opacity: 0, height: 0 }}
                          className="group flex flex-col py-4 border-b border-border last:border-0"
                        >
                          <div className="flex items-center justify-between">
                            <div className="flex items-center gap-4">
                              <button
                                onClick={() => toggleToday(habit.id)}
                                className={`flex items-center justify-center h-5 w-5 rounded border transition-colors ${
                                  completed 
                                    ? "bg-accent border-accent text-background" 
                                    : "border-border hover:border-accent hover:bg-accent/10 text-transparent"
                                }`}
                              >
                                <Check className="h-3 w-3" />
                              </button>
                              <div className="flex flex-col">
                                <span className={`text-[14px] font-medium transition-colors ${completed ? "text-text-primary" : "text-text-secondary"}`}>
                                  {habit.name}
                                </span>
                                <span className="text-[11px] text-text-tertiary mt-0.5">
                                  {rate}% · Streak: {streak.current}d
                                </span>
                              </div>
                            </div>

                            <div className="flex items-center gap-3">
                              {!habit.preset && (
                                <button onClick={() => removeHabit(habit.id)} className="opacity-0 group-hover:opacity-100 transition-opacity text-text-tertiary hover:text-destructive">
                                  <Trash2 className="h-3.5 w-3.5" />
                                </button>
                              )}
                            </div>
                          </div>
                        </motion.div>
                      );
                    })
                  ) : (
                    <div className="py-12 text-center text-[13px] text-text-tertiary">No habits tracked yet.</div>
                  )}
                </AnimatePresence>
              </div>
            </section>

            <section className="rounded-xl border border-border bg-surface p-6 shadow-card hover:border-border-hover transition-all duration-200">
              <h2 className="text-[14px] font-medium text-text-primary mb-6">Activity Heatmap</h2>
              <div className="grid grid-cols-7 gap-2">
                {gridDays.map((date) => {
                  const key = toDateKey(date);
                  const count = heatmapCounts.get(key) ?? 0;
                  return (
                    <div
                      key={key}
                      className="group relative flex aspect-square items-center justify-center rounded-md border border-border text-[10px] text-text-secondary font-medium transition"
                      title={`${formatMonthLabel(date)} · ${count} completions`}
                      style={{
                        background:
                          count === 0
                            ? "transparent"
                            : count === 1
                              ? "rgba(203,163,101,0.16)"
                              : count === 2
                                ? "rgba(203,163,101,0.28)"
                                : "rgba(203,163,101,0.5)",
                      }}
                    >
                      <span>{date.getDate()}</span>
                    </div>
                  );
                })}
              </div>
            </section>
          </motion.div>

          {/* RIGHT: Add Habit & Snapshot */}
          <motion.div variants={staggerItem} className="flex flex-col gap-8">
            <section className="rounded-xl border border-border bg-surface p-6 shadow-card hover:border-border-hover transition-all duration-200">
              <h2 className="text-[14px] font-medium text-text-primary mb-6">Manage Habits</h2>

              <div className="space-y-4">
                <div className="space-y-2">
                  <label className="text-[12px] font-medium text-text-secondary">New Habit</label>
                  <div className="flex gap-2">
                    <input
                      type="text"
                      className="flex-1 h-9 bg-background border border-border rounded-md px-3 text-[13px] text-text-primary focus:outline focus:outline-2 focus:outline-accent outline-offset-0 placeholder:text-text-tertiary transition-all"
                      placeholder="E.g., Read 10 pages"
                      value={newHabitName}
                      onChange={(e) => setNewHabitName(e.target.value)}
                      onKeyDown={(e) => e.key === "Enter" && addHabit()}
                    />
                    <button onClick={addHabit} className="h-9 px-4 bg-accent text-background rounded-md text-[13px] font-semibold hover:opacity-90 transition-opacity">
                      Add
                    </button>
                  </div>
                </div>

                <div className="pt-4 border-t border-border space-y-2">
                  <label className="text-[12px] font-medium text-text-secondary">Search</label>
                  <div className="relative">
                    <Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-text-tertiary" />
                    <input
                      type="text"
                      className="w-full h-9 bg-background border border-border rounded-md pl-9 pr-3 text-[13px] text-text-primary focus:outline focus:outline-2 focus:outline-accent outline-offset-0 placeholder:text-text-tertiary transition-all"
                      placeholder="Filter habits..."
                      value={search}
                      onChange={(e) => setSearch(e.target.value)}
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[12px] font-medium text-text-secondary">Focus Metrics</label>
                  <select
                    className="h-9 w-full bg-background border border-border rounded-md px-3 text-[13px] text-text-primary focus:outline focus:outline-2 focus:outline-accent outline-offset-0 transition-all"
                    value={selectedHabitId}
                    onChange={(e) => setSelectedHabitId(e.target.value)}
                  >
                    {habits.map((h) => <option key={h.id} value={h.id}>{h.name}</option>)}
                  </select>
                </div>
              </div>
            </section>

            <section className="rounded-xl border border-border bg-surface p-6 shadow-card hover:border-border-hover transition-all duration-200">
              <h2 className="text-[14px] font-medium text-text-primary mb-6">Weekly Progress</h2>

              <div className="space-y-4">
                {pastSevenDays.map((date) => {
                  const key = toDateKey(date);
                  const count = heatmapCounts.get(key) ?? 0;
                  const percent = habits.length ? (count / habits.length) * 100 : 0;

                  return (
                    <div key={key} className="flex flex-col gap-1.5">
                      <div className="flex items-center justify-between text-[11px] font-medium uppercase tracking-widest text-text-tertiary">
                        <span>{formatDayLabel(date)}</span>
                        <span>{count}/{habits.length}</span>
                      </div>
                      <div className="h-1.5 w-full bg-background rounded-full overflow-hidden border border-border">
                        <div 
                          className="h-full bg-accent rounded-full transition-all duration-500"
                          style={{ width: `${percent}%` }}
                        />
                      </div>
                    </div>
                  );
                })}
              </div>
            </section>
          </motion.div>
        </div>
      </motion.div>
    </div>
  );
}

"use client";

import { zodResolver } from "@hookform/resolvers/zod";
