}

function FormError({ message }: { message?: string }) {
  if (!message) return null;
  return <p className="text-[11px] text-destructive mt-1">{message}</p>;
}

import { doc, getDoc, setDoc } from "firebase/firestore";
import type { ActiveTimer, TimeEntry } from "@/features/time-tracker/time-tracker-types";

const STORAGE_KEY = "careeros.time-tracker.v1";
import { db } from "@/lib/firebase";

export type TimeTrackerState = {
  entries: TimeEntry[];
  activeTimer: ActiveTimer | null;
};

export const defaultTimeTrackerState: TimeTrackerState = {
  entries: [],
  activeTimer: null,
};

export async function loadTimeTrackerState(userId: string): Promise<TimeTrackerState> {
  if (!db || !userId) return { entries: [], activeTimer: null };
  try {
    const docRef = doc(db, "users", userId, "time-tracker", "state");
    const snap = await getDoc(docRef);
    if (snap.exists()) {
      return snap.data() as TimeTrackerState;
    }
  } catch (error) {
    console.error("Failed to load time tracker from Firestore:", error);
  }
  return { entries: [], activeTimer: null };
}

export async function saveTimeTrackerState(userId: string, state: TimeTrackerState) {
  if (!db || !userId) return;
  try {
    const docRef = doc(db, "users", userId, "time-tracker", "state");
    await setDoc(docRef, state, { merge: true });
  } catch (error) {
    console.error("Failed to save time tracker to Firestore:", error);
  }
}

import { toDateInputValue } from "@/features/time-tracker/time-tracker-utils";

function generateMockTimeState() {
  const entries = [];
  let currentId = 1;
  const today = new Date();

  // We need ~188 hours total. 
  // Let's do 4 hours a day for the past 40 days, and 5 hours for the past 7 days.
  for (let i = 47; i >= 0; i--) {
    const d = new Date(today);
    d.setDate(d.getDate() - i);
    const dateStr = toDateInputValue(d);

    // Add 4 hours
    entries.push({
      id: String(currentId++),
      date: dateStr,
      duration: 4 * 3600000,
      task: "Deep Work",
      createdAt: d.toISOString()
    });
  }

  return { entries };
}

function generateMockDsaProblems() {
  const problems = [];
  const topics = ["Arrays & Hashing", "Two Pointers", "Sliding Window", "Stack", "Binary Search", "Linked List", "Trees", "Tries", "Heap / Priority Queue", "Backtracking", "Graphs", "1-D DP", "2-D DP", "Greedy", "Intervals", "Math & Geometry", "Bit Manipulation"];
  const difficulties = ["Easy", "Medium", "Hard"];
  const today = new Date();

  for (let i = 1; i <= 323; i++) {
    const topic = topics[i % topics.length];
    const difficulty = i % 5 === 0 ? "Hard" : (i % 2 === 0 ? "Medium" : "Easy");

    const solvedDate = new Date(today);
    solvedDate.setDate(solvedDate.getDate() - Math.floor(Math.random() * 100)); // random date in past 100 days

    problems.push({
      id: `mock-prob-${i}`,
      title: `LeetCode Problem ${i}`,
      url: "https://leetcode.com/problems/mock-problem",
      difficulty,
      topic,
      solvedDate: toDateInputValue(solvedDate),
      timeSpentMs: Math.random() * 30 * 60000 // 0-30 mins
    });
  }
  return problems;
}

